//     to a project and are not touched here.

// The generic uniform READ contract (spec uniform-entity-verbs v2): every entity family
// exposes ONE read verb — search — where `list` is simply a search WITHOUT a query and
// `relevance` is a sort option that only exists WITH a query. The contract is a shared
// SHAPE, not a DI seam: modules implement ISearchService explicitly on their own service
// (no polymorphic dispatch), adapters (MCP tools) stay thin — parse params, call the
// service, budget + shape the response.

// One read response: the selected rows plus the two cross-cutting envelopes every read
// carries — the RESPONSE BUDGET markers (Truncated/Omitted/Hint; see ResponseBudget —
// null = complete answer, so an in-budget response serializes without them) and the
// retriever PROVENANCE (which retrievers ran / degraded; null in listing mode, where no
// retriever is involved).
public sealed record SearchEnvelope<TEntity>(
	IReadOnlyList<TEntity> Items,
	bool? Truncated = null,
	int? Omitted = null,
	string? Hint = null,
	SearchRetrievers? Retrievers = null);

// One response-wide char budget for list-shaped tool results (spec surface-economy /
// bounded-result-sets): a read built for agents must stay inside a context window no
// matter how large the store grows — and never truncate silently. Row costs are measured
// on the WIRE form of each row (camelCase JSON, null fields omitted — mirroring the MCP
// serializer defaults), rows are prefix-cut at the first one that no longer fits, and the
// caller marks the cut structurally (truncated:true + omitted:<n> + a narrowing hint).
// One instance = one response: spending accumulates across Take calls, so several lists
// (e.g. the four methodology boards) share a single budget in emission order. Shared by
// tasks_search / tasks_methodology_get / memory_search / session_search / comments_search.
public sealed class ResponseBudget
{
	// Default budget: ~30k serialized chars keeps a tool result well inside an agent's
	// context window while leaving room for the response envelope.
	public const int DefaultChars = 30_000;

// The one door into search, in front of N pluggable indexes. It routes the write path by
// consistency class and fuses the read path with provenance — so consumers (memory, tasks,
// session) speak one entity-addressed contract regardless of which/where the indexes are
// (spec: search-service umbrella). Design: memory m-b3fbe908 (classes) + m-1a5c37fe (fusion).
//
//   Write — Synchronous indexes run INLINE on the caller's entity transaction (the lexical
//     floor commits/rolls back with the entity). Eventual indexes are NOT driven here: they
//     subscribe to the temporal log via their own cursor (async-vectorization) — a separate
//     work item; the facade simply skips them on write.
//   Read  — poll every index, RRF-fuse their ranked id lists (reuse HybridMerge), and report
//     which retrievers ran + whether the result is degraded.

// The consistency class of an index's write path — the load-bearing distinction of the
// search contract (design: memory m-b3fbe908).
//   Synchronous = the lexical floor: updated INSIDE the entity's DB transaction (same
//     SQLite file/connection), commits/rolls back WITH the entity → a committed entity is
//     never lexically-stale. MUST be local (transactional ⊥ remote; no 2PC).
//   Eventual    = vector / episodic enrichment: materialized later by a background worker
//     that subscribes to the temporal log via its own cursor (async-vectorization). May be
//     remote/pluggable; best-effort; search degrades gracefully when it is behind or absent.
public enum SearchConsistency
{
	Synchronous,
	Eventual,
}

// Provenance for a search response: which retrievers actually ran and whether the
// result is degraded (e.g. the semantic retriever was requested but embedding was
// unavailable, so only lexical ran). Surfaced so callers can honestly say
// "vector unavailable → only FTS ran" rather than silently returning lexical-only.
public readonly record struct SearchRetrievers(bool Lexical, bool Semantic, bool Degraded);

// Shared FTS5 query builder. Lenient MATCH expression: Unicode word tokens
// (letters/digits — Latin, Cyrillic, …), prefix-matched (tok*) and ANDed. An FTS5
// unicode61 table case-folds and strips diacritics, so the query tokenizer must NOT
// drop non-ASCII: a `[a-z0-9]` class would silently discard a Russian query and return
// nothing (the bug fixed in memory/tasks; lifted here so every Class-A index shares the
// fix — spec: search-lexical-multilingual).

// Async materialization of Class-B (enriching) indexes — the write path NEVER blocks on
// embedding (spec: write-never-blocks). A Class-B index is just a delta SUBSCRIBER with its own
// cursor over the entity's existing temporal version log: no separate outbox table, per-index
// state is one number. An embedder outage stalls the cursor; on recovery it drains forward =
// automatic backfill with no lost writes (spec: durable-backfill). A poison item (always fails)
// is dead-lettered after N attempts so it can't head-of-line-block the cursor. Design: m-1a5c37fe.

// Declarative, append-only upsert for a batch of keyed rows.
//
// Each desired row carries a WATERMARK baseline in Version: the version the author
// last saw for THIS entity, OR the scope cursor (currentVersion) from their last read
// of the whole scope — either is a valid baseline (Version == 0 = "new, read nothing").
// Optimistic concurrency is a watermark, not an exact match — and it guards PAYLOAD,
// not version arithmetic:
//   * an EDIT applies when its baseline is AT OR AFTER the entity's current revision
//     (the entity was unchanged since the author's read);
//   * a payload IDENTICAL to the current revision is a no-op on any non-future baseline —
//     the store already holds what the author wants (a resubmit, an identical concurrent
//     edit, or an FSM effect that got there first), so there is nothing to protect;
//   * a baseline BEHIND the entity's revision is Stale only when the payload moved
//     SEMANTICALLY after the author's read; if the intervening revisions left the payload
//     as the author read it (bookkeeping rewrites, A→B→A), the edit applies and the key is
//     reported in AutoResolved. A genuine Stale carries ChangedFields — the entity's own
//     fields that moved — so the retry is informed, not blind;
//   * a CREATE (no active row) applies for ANY baseline ≤ the scope cursor, 0 included —
//     there is nothing to clobber;
//   * a baseline ABOVE the scope cursor is a FutureBaseline conflict — the author is
//     quoting a version this scope never reached, usually a cursor from another
//     board/store. Checked before everything, including the identical-payload no-op.
// So a caller may stamp every row in a batch with the single scope currentVersion it
// last read: the touched entity applies, untouched entities collapse to no-ops, and only
// a genuine concurrent change to a specific entity rejects. Any conflict aborts the whole
// batch; conflicts are returned so the caller rebases.

// Result of an upsert. Besides what was applied, carries the delta the caller
// asked for via `sinceVersion`: every active row that changed since that cursor
// (own edits AND others'), split into Added/Updated, plus keys that died. The
// caller advances its single cursor to CurrentVersion without re-reading.
public sealed record TemporalUpsertResult<TRow>(
	bool Applied,
	long CurrentVersion,
	int Inserted,
	int Closed,
	IReadOnlyList<TemporalConflict> Conflicts,
	IReadOnlyList<TRow> Added,
	IReadOnlyList<TRow> Updated,
	IReadOnlyList<string> Removed,
	// Keys whose baseline was stale but whose entity payload had NOT semantically moved
	// since the author's read (bookkeeping rewrites only, incl. A→B→A) — applied instead
	// of conflicting, and reported here so the resolution stays visible, never silent.
	IReadOnlyList<string> AutoResolved)
	where TRow : TemporalRow

// Keys whose baseline was stale but whose entity payload had NOT semantically moved
	// since the author's read (bookkeeping rewrites only, incl. A→B→A) — applied instead
	// of conflicting, and reported here so the resolution stays visible, never silent.
	IReadOnlyList<string> AutoResolved)

// onWithinTx (when set) fires INSIDE the apply transaction, after the new revisions are
	// inserted and before commit, with the rows upserted this batch and the keys whose active
	// row was closed without a replacement (soft-deletes + rename sources). It is the seam the
	// Class-A search floor rides: writing the lexical index here commits/rolls back WITH the
	// entity, so a committed entity is never lexically-stale and a throw rolls both back together.

// When true, the property type must be string and its value is stored as
	// base64(cipher+iv+tag) via ISecretEncryptor. UI renders as password input + reveal.
	public bool IsSecret { get; init; }

